
import { ValidateErrorEntity } from "ant-design-vue/es/form/interface";
import { Moment } from "moment";
import {
  defineComponent,
  inject,
  reactive,
  ref,
  toRaw,
  toRefs,
  UnwrapRef,
} from "vue";
import { saveMessage } from "@/server/http/api/Amultitasking";
interface FormState {
  reportType: string;
  reportTime: Moment;
  addressee: Moment;
  reportPhone: string;
  reportMailingAddress: string;
  waybill: string;
  email: string;
  id: number;
}

export default defineComponent({
  props: ["detail"],
  setup(props) {
    let init: any = inject("init");
    const formRef = ref();
    const formState: UnwrapRef<any> = reactive({
      reportType: "邮寄",
      reportTime: undefined,
      addressee: null,
      reportMailingAddress: null,
      reportPhone: null,
      waybill: null,
      email: null,
      id: null,
    });
    const rules = {
      name: [
        {
          required: true,
          message: "此项必填项",
          trigger: "blur",
        },
        { max: 64, message: "超出字符限制", trigger: "blur" },
      ],
    };
    // const onSubmit = () => {
    //   formRef.value
    //     .validate()
    //     .then(() => {
    //       //console.log("values", formState, toRaw(formState));
    //     })
    //     .catch((error: ValidateErrorEntity<FormState>) => {
    //       //console.log("error", error);
    //     });
    // };

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = () => {
      formState.id = props.detail.id;
      formState.reportType = props.detail.reportType;
      formState.reportTime = props.detail.reportTime;
      formState.reportPhone = props.detail.reportPhone;

      formState.addressee = props.detail.addressee;
      formState.reportMailingAddress = props.detail.reportMailingAddress;
      formState.waybill = props.detail.waybill;
      formState.email = props.detail.email;

      visible.value = true;
    };

    const handleOk = () => {
      //console.log(formState);
      confirmLoading.value = true;

      saveMessage(toRaw(formState)).then((res: any) => {
        if (res.data.code === 200) {
          init();
        }
        visible.value = false;
        confirmLoading.value = false;
      });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      formRef,
      labelCol: { span: 6 },
      wrapperCol: { span: 12 },
      other: "",
      formState,
      rules,

      //   onSubmit,
    };
  },
});
