import { defineComponent, provide, reactive, ref, toRefs, watch } from "vue";
import { sendList, addSeal } from "@/server/http/api/Amultitasking";
import CheckDetail from "./model/Reportgeneration/CheckDetail.vue";
import CheckUpdate from "./model/Reportmailing/CheckUpdate.vue";
export default defineComponent({
  name: "Reportmailing",
  components: { CheckDetail, CheckUpdate },
  setup() {
    let searchValue = ref("");
    let datatList = ref([]);
    let searchOption = reactive({
      active: 1,
      pageNum: 1,
      pageSize: 10,
      reportType: "邮寄",
    });
    let total = ref(0);

    // 搜索函数
    function searchData() {
      sendList({
        type: searchOption.active,
        search: searchValue.value,
        pageNum: searchOption.pageNum,
        pageSize: searchOption.pageSize,
        reportType: searchOption.reportType,
      }).then((res: any) => {
        //console.log(res);

        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    // 搜索条件
    let timer: any;
    watch(searchValue, () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        searchData();
      }, 400);
    });
    // 分页搜索
    watch(
      searchOption,
      () => {
        searchData();
      },
      {
        immediate: true,
      }
    );
    provide("init", searchData);
    function onSearch() {}
    return {
      onSearch,
      searchValue,
      datatList,
      columns,
      columns1,
      total,
      ...toRefs(searchOption),
    };
  },
});
